import { Navigate, Outlet } from 'react-router-dom';
import { useEffect, useRef } from 'react';
import { useQuery } from '@tanstack/react-query';
import { ServerCrash, RefreshCw } from 'lucide-react';
import { useAuth } from '@/shared/AuthContext';
import { aboutService } from '@/api/aboutService';
import { Button } from '@/shadcn/components/ui/button';
import { queryKeys } from '@/lib/queryKeys';
import { HarmonyApiStatus } from '@/components/ui/harmony-api-status';

const ProtectedRoute = () => {
  const { user, isLoading, backgroundRefreshPermissions } = useAuth();

  const {
    data: health,
    isError: apiUnreachable,
    isPending: healthPending,
    isFetching: healthFetching,
    isSuccess: healthSuccess,
    refetch: retryHealth,
  } = useQuery({
    queryKey: queryKeys.health(),
    queryFn: aboutService.getHealth,
    retry: 0,
    enabled: !!user,
    refetchInterval: 60_000,
    refetchIntervalInBackground: false,
  });

  const retryHealthRef = useRef(retryHealth);
  retryHealthRef.current = retryHealth;
  const failureCountRef = useRef(0);

  // Track whether the server has ever been confirmed down in this session.
  // Updated synchronously during render so the Server Unavailable page persists
  // through TQ v5's brief 'pending' phase when retryHealth() is called (which
  // sets isError=false transiently before the refetch resolves).
  const everFailedRef = useRef(false);
  if (apiUnreachable) everFailedRef.current = true;
  if (health && healthSuccess) everFailedRef.current = false;

  // Separate ref that stays true until the recovery effect consumes it.
  // everFailedRef resets synchronously on render (before effects run), so it
  // can't be used inside a useEffect to detect the failed→recovered transition.
  const hadFailureRef = useRef(false);
  if (apiUnreachable) hadFailureRef.current = true;

  useEffect(() => {
    if (!user || !apiUnreachable || healthFetching) {
      // Reset counter only when the server is genuinely back (isSuccess), not on the
      // transient !isError state that TQ v5 produces while a retry is in-flight.
      if (healthSuccess) failureCountRef.current = 0;
      return;
    }
    const n = failureCountRef.current;
    const delay = Math.min(10_000 * Math.pow(2, n), 60_000);
    const id = setTimeout(() => {
      failureCountRef.current += 1;
      retryHealthRef.current();
    }, delay);
    return () => clearTimeout(id);
  }, [user, apiUnreachable, healthFetching, healthSuccess]);

  // When the API recovers after a failure, refresh permissions so the sidebar
  // reflects the correct state without requiring a manual navigation.
  useEffect(() => {
    if (health && hadFailureRef.current && user) {
      hadFailureRef.current = false;
      backgroundRefreshPermissions();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [health]);

  // Use everFailedRef (not apiUnreachable) so this stays true through the brief
  // TQ pending phase during retries — prevents a spinner flash on every attempt.
  if (user && everFailedRef.current) {
    return (
      <div className="flex min-h-screen flex-col items-center justify-center gap-6 bg-background">
        <div className="fixed top-4 right-4 z-50">
          <HarmonyApiStatus />
        </div>
        <div className="flex flex-col items-center gap-3 text-center">
          <ServerCrash className="h-12 w-12 text-muted-foreground" />
          <h1 className="text-xl font-semibold">Server Unavailable</h1>
          <p className="max-w-sm text-sm text-muted-foreground">
            The server is currently unreachable. The app will reconnect automatically.
          </p>
        </div>
        <Button variant="outline" size="sm" onClick={() => retryHealth()}>
          <RefreshCw className="mr-2 h-4 w-4" />
          Try again
        </Button>
      </div>
    );
  }

  if (isLoading || (!!user && healthPending)) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-background">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;
};

export default ProtectedRoute;
